// 1. Get the date for exactly 7 days ago
const sevenDaysAgo = new Date();
sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
sevenDaysAgo.setHours(0, 0, 0, 0);

const weeklyData = [];

for (const item of items) {
  const rowDate = new Date(item.json.Date);

  if (rowDate >= sevenDaysAgo) {
    weeklyData.push({
      json: {
        ...item.json,
        aiContext: `${item.json['Campaign Name']} sent on ${item.json.Date} had a ${item.json['Open Rate']} open rate.`
      }
    });
  }
}

return weeklyData;

const campaigns = items[0].json.campaigns || [];

return campaigns.map(campaign => {
  const stats = campaign.statistics.campaignStats[0] || {};

  const sent = stats.sent || 0;
  const delivered = stats.delivered || 0;
  const opens = stats.uniqueViews || 0;
  const clicks = stats.uniqueClicks || 0;
  const bounces = (stats.softBounces || 0) + (stats.hardBounces || 0);

  const openRate = delivered > 0 ? (opens / delivered) : 0;
  const clickRate = delivered > 0 ? (clicks / delivered) : 0;
  const bounceRate = delivered > 0 ? (bounces / delivered) : 0;

  return {
    json: {
      "Campaign Name": campaign.name,
      "Date": campaign.sentDate.split('T')[0],
      "Sent": sent,
      "Delivered": delivered,
      "Open Rate": openRate,
      "Click Rate": clickRate,
      "Bounce Rate": bounceRate
    }
  };
});
